import { Mastra } from '@mastra/core';
import { Agent } from '@mastra/core/agent';
import { openai } from '@ai-sdk/openai';
import { anthropic } from '@ai-sdk/anthropic';
import fs from 'fs';
import path from 'path';
import dotenv from 'dotenv';

dotenv.config();

const openaiAgent = new Agent({
  name: 'openai-agent',
  instructions: 'You are an OpenAI assistant.',
  model: openai('gpt-4o'),
});

const anthropicAgent = new Agent({
  name: 'anthropic-agent',
  instructions: 'You are an Anthropic assistant.',
  model: anthropic('claude-3-5-sonnet-20240620'),
});

const mastra = new Mastra({
  agents: [openaiAgent, anthropicAgent],
});

async function main() {
  const logPath = '/home/user/mastra-multi-model/output.log';

  try {
    console.log('Prompting OpenAI agent...');
    const openaiResult = await openaiAgent.generate('Say hello');
    const openaiResponse = openaiResult.text;

    console.log('Prompting Anthropic agent...');
    const anthropicResult = await anthropicAgent.generate('Say hello');
    const anthropicResponse = anthropicResult.text;

    const logContent = `OpenAI Agent Response: ${openaiResponse}\n\nAnthropic Agent Response: ${anthropicResponse}\n`;

    fs.writeFileSync(logPath, logContent);
    console.log(`Responses saved to ${logPath}`);
  } catch (error) {
    console.error('Error running agents:', error);
    // If it fails, I'll log why to the log file as well, for debugging
    fs.writeFileSync(logPath, `Error: ${error.message}\nEnsure OPENAI_API_KEY and ANTHROPIC_API_KEY are set.`);
  }
}

main();

